**Queue Implementation using Two Stacks in Python**
=====================================================

We will implement a queue data structure using two stacks in Python. This implementation will utilize two stack data structures to simulate the enqueue and dequeue operations of a queue.

```python
class Stack:
    """A basic stack implementation."""

    def __init__(self):
        """Initialize an empty stack."""
        self.stack = []

    def push(self, value):
        """Add an element to the top of the stack."""
        self.stack.append(value)

    def pop(self):
        """Remove and return the top element from the stack."""
        if not self.is_empty():
            return self.stack.pop()
        else:
            raise IndexError("Stack is empty")

    def peek(self):
        """Return the top element from the stack without removing it."""
        if not self.is_empty():
            return self.stack[-1]
        else:
            raise IndexError("Stack is empty")

    def is_empty(self):
        """Check if the stack is empty."""
        return len(self.stack) == 0


class Queue:
    """A queue implementation using two stacks."""

    def __init__(self):
        """Initialize an empty queue."""
        self.stack1 = Stack()
        self.stack2 = Stack()

    def enqueue(self, value):
        """Add an element to the end of the queue."""
        self.stack1.push(value)

    def dequeue(self):
        """Remove and return the front element from the queue."""
        if self.stack2.is_empty():
            while not self.stack1.is_empty():
                self.stack2.push(self.stack1.pop())
        if self.stack2.is_empty():
            raise IndexError("Queue is empty")
        return self.stack2.pop()

    def peek(self):
        """Return the front element from the queue without removing it."""
        if self.stack2.is_empty():
            if self.stack1.is_empty():
                raise IndexError("Queue is empty")
            while not self.stack2.is_empty():
                self.stack2.push(self.stack1.pop())
        return self.stack2.peek()

    def is_empty(self):
        """Check if the queue is empty."""
        return self.stack1.is_empty() and self.stack2.is_empty()


# Example usage:
queue = Queue()
queue.enqueue(1)
queue.enqueue(2)
queue.enqueue(3)

print(queue.dequeue())  # prints 1
print(queue.peek())     # prints 2
print(queue.dequeue())  # prints 2
print(queue.dequeue())  # prints 3
```

